#!/usr/bin/env bash

# =========================================================
# Step 06. Create GVCF sample map for GenomicsDBImport
# Project: Integrated MRONJ risk prediction model
# Input:
#   Per-sample GVCF files generated by GATK HaplotypeCaller
# Output:
#   GVCF sample map file for GATK GenomicsDBImport
# =========================================================

set -euo pipefail

SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/00_config.sh"

echo "[Step 06] Creating GVCF sample map"
echo "Input GVCF directory: ${GVCF_DIR}"
echo "Output sample map   : ${SAMPLE_MAP}"

shopt -s nullglob

gvcf_files=("${GVCF_DIR}"/*.g.vcf.gz)

if [ ${#gvcf_files[@]} -eq 0 ]; then
    echo "ERROR: No GVCF files found in ${GVCF_DIR}" >&2
    exit 1
fi

rm -f "${SAMPLE_MAP}"

for gvcf_file in "${gvcf_files[@]}"; do
    sample_name="$(basename "${gvcf_file}" .g.vcf.gz)"

    if [ ! -f "${gvcf_file}.tbi" ]; then
        echo "WARNING: Index file not found for ${gvcf_file}. Creating index." >&2
        gatk IndexFeatureFile \
            -I "${gvcf_file}" \
            > "${LOG_DIR}/${sample_name}.index_gvcf.log" 2>&1
    fi

    printf "%s\t%s\n" "${sample_name}" "${gvcf_file}" >> "${SAMPLE_MAP}"
done

echo "Generated sample map:"
cat "${SAMPLE_MAP}"

echo "[Step 06] GVCF sample map creation completed."
